class Solution:
    def findLongestWord(self, s, dictionary):
        def is_sub(w):
            i = 0
            for ch in s:
                if i < len(w) and w[i] == ch:
                    i += 1
            return i == len(w)
        best = ''
        for w in dictionary:
            if is_sub(w):
                if len(w) > len(best) or (len(w) == len(best) and w < best):
                    best = w
        return best

