class Solution:
    def findLongestWord(self, s, dictionary):
        def is_sub(w):
            it = iter(s)
            return all(c in it for c in w)
        best = ''
        for w in sorted(dictionary, key=lambda x: (-len(x), x)):
            if is_sub(w):
                return w
        return best

