var findLongestWord = function(s, dictionary) {
    const isSub = (w) => {
        let i = 0;
        for (const ch of s) {
            if (i < w.length && w[i] === ch) i++;
        }
        return i === w.length;
    };
    const sorted = dictionary.slice().sort((a, b) => b.length - a.length || (a < b ? -1 : a > b ? 1 : 0));
    for (const w of sorted) {
        if (isSub(w)) return w;
    }
    return '';
};
